import { useState, useEffect } from 'react';
import { X } from 'lucide-react';
import { useTimeTrackingStore } from '../stores/useTimeTrackingStore';
import { ProjectSelector } from './ProjectSelector';
import type { TimeEntry } from '../types';

interface EditTimeEntryModalProps {
  entry: TimeEntry;
  onClose: () => void;
}

/**
 * EditTimeEntryModal Component
 * Modal dialog for editing existing time entries
 */
export function EditTimeEntryModal({ entry, onClose }: EditTimeEntryModalProps) {
  const { updateEntry } = useTimeTrackingStore();

  const [description, setDescription] = useState(entry.description);
  const [startTime, setStartTime] = useState('');
  const [endTime, setEndTime] = useState('');
  const [projectId, setProjectId] = useState<string | null>(entry.projectId || null);
  const [notes, setNotes] = useState(entry.notes || '');
  const [billable, setBillable] = useState(entry.billable || false);
  const [hourlyRate, setHourlyRate] = useState(entry.hourlyRate?.toString() || '');
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    // Format times for datetime-local input
    const formatDateTimeLocal = (isoString: string) => {
      const date = new Date(isoString);
      return date.toISOString().slice(0, 16);
    };

    setStartTime(formatDateTimeLocal(entry.startTime));
    if (entry.endTime) {
      setEndTime(formatDateTimeLocal(entry.endTime));
    }
  }, [entry]);

  const handleSave = async () => {
    setError('');

    // Validation
    if (!description.trim()) {
      setError('Description is required');
      return;
    }

    if (!startTime) {
      setError('Start time is required');
      return;
    }

    if (!endTime) {
      setError('End time is required');
      return;
    }

    const startDate = new Date(startTime);
    const endDate = new Date(endTime);

    if (endDate <= startDate) {
      setError('End time must be after start time');
      return;
    }

    setSaving(true);
    try {
      // Calculate new duration
      const newDuration = Math.floor((endDate.getTime() - startDate.getTime()) / 1000);

      await updateEntry(entry.id, {
        description: description.trim(),
        startTime: startDate.toISOString(),
        endTime: endDate.toISOString(),
        duration: newDuration,
        projectId: projectId || undefined,
        notes: notes.trim() || undefined,
        billable,
        hourlyRate: hourlyRate ? parseFloat(hourlyRate) : undefined
      });

      onClose();
    } catch (err) {
      console.error('Failed to update entry:', err);
      setError('Failed to save changes. Please try again.');
    } finally {
      setSaving(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Escape') {
      onClose();
    } else if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) {
      handleSave();
    }
  };

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4"
      onClick={onClose}
    >
      <div
        className="bg-surface-light dark:bg-surface-dark rounded-button border border-border-light dark:border-border-dark shadow-xl max-w-md w-full"
        onClick={(e) => e.stopPropagation()}
        onKeyDown={handleKeyDown}
      >
        {/* Header */}
        <div className="flex items-center justify-between px-4 py-3 border-b border-border-light dark:border-border-dark">
          <h2 className="text-base font-semibold text-text-light-primary dark:text-text-dark-primary">
            Edit Time Entry
          </h2>
          <button
            onClick={onClose}
            className="p-1 rounded-button hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary transition-all duration-standard ease-smooth"
            aria-label="Close modal"
          >
            <X className="w-4 h-4" />
          </button>
        </div>

        {/* Body */}
        <div className="p-4 space-y-3">
          {error && (
            <div className="px-3 py-2 bg-status-error/10 border border-status-error/20 rounded-button text-status-error text-xs">
              {error}
            </div>
          )}

          {/* Description */}
          <div>
            <label
              htmlFor="description"
              className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5"
            >
              Description
            </label>
            <input
              id="description"
              type="text"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              className="w-full px-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary"
              placeholder="What did you work on?"
            />
          </div>

          {/* Start Time */}
          <div>
            <label
              htmlFor="startTime"
              className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5"
            >
              Start Time
            </label>
            <input
              id="startTime"
              type="datetime-local"
              value={startTime}
              onChange={(e) => setStartTime(e.target.value)}
              className="w-full px-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
            />
          </div>

          {/* End Time */}
          <div>
            <label
              htmlFor="endTime"
              className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5"
            >
              End Time
            </label>
            <input
              id="endTime"
              type="datetime-local"
              value={endTime}
              onChange={(e) => setEndTime(e.target.value)}
              className="w-full px-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
            />
          </div>

          {/* Project */}
          <div>
            <label
              htmlFor="project"
              className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5"
            >
              Project
            </label>
            <ProjectSelector
              value={projectId}
              onChange={setProjectId}
              placeholder="No Project"
              showNoProject={true}
            />
          </div>

          {/* Notes */}
          <div>
            <label
              htmlFor="notes"
              className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5"
            >
              Notes (Optional)
            </label>
            <textarea
              id="notes"
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              rows={2}
              className="w-full px-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary resize-none"
              placeholder="Add additional details about this time entry..."
            />
          </div>

          {/* Billable Toggle */}
          <div className="flex items-center gap-2">
            <input
              id="billable"
              type="checkbox"
              checked={billable}
              onChange={(e) => setBillable(e.target.checked)}
              className="w-4 h-4 text-accent-magenta dark:text-accent-cyan bg-surface-light-elevated dark:bg-surface-dark-elevated border-border-light dark:border-border-dark rounded focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan"
            />
            <label
              htmlFor="billable"
              className="text-xs font-medium text-text-light-primary dark:text-text-dark-primary cursor-pointer"
            >
              Billable time
            </label>
          </div>

          {/* Hourly Rate (only show if billable) */}
          {billable && (
            <div>
              <label
                htmlFor="hourlyRate"
                className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5"
              >
                Hourly Rate <span className="text-text-light-tertiary dark:text-text-dark-tertiary font-normal">(optional)</span>
              </label>
              <div className="relative">
                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-text-light-secondary dark:text-text-dark-secondary text-xs">
                  $
                </span>
                <input
                  id="hourlyRate"
                  type="number"
                  min="0"
                  step="0.01"
                  value={hourlyRate}
                  onChange={(e) => setHourlyRate(e.target.value)}
                  className="w-full pl-6 pr-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary"
                  placeholder="0.00"
                />
              </div>
            </div>
          )}

          {/* Duration Preview */}
          {startTime && endTime && (
            <div className="px-2.5 py-2 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-button border border-border-light dark:border-border-dark">
              <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                Duration:{' '}
                <span className="font-mono font-semibold text-accent-magenta dark:text-accent-cyan">
                  {(() => {
                    const start = new Date(startTime).getTime();
                    const end = new Date(endTime).getTime();
                    const durationSeconds = Math.floor((end - start) / 1000);
                    const hours = Math.floor(durationSeconds / 3600);
                    const minutes = Math.floor((durationSeconds % 3600) / 60);
                    return `${hours}h ${minutes.toString().padStart(2, '0')}m`;
                  })()}
                </span>
              </div>
              {billable && hourlyRate && (
                <div className="text-xs text-status-success-text font-medium mt-1">
                  Estimated Revenue: ${(() => {
                    const start = new Date(startTime).getTime();
                    const end = new Date(endTime).getTime();
                    const durationSeconds = Math.floor((end - start) / 1000);
                    return ((durationSeconds / 3600) * parseFloat(hourlyRate)).toFixed(2);
                  })()}
                </div>
              )}
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="flex items-center justify-end gap-2 px-4 py-3 border-t border-border-light dark:border-border-dark">
          <button
            onClick={onClose}
            disabled={saving}
            className="px-3 py-1.5 text-xs font-medium text-text-light-primary dark:text-text-dark-primary bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button hover:bg-surface-light dark:hover:bg-neutral-800 transition-all duration-standard ease-smooth disabled:opacity-50"
          >
            Cancel
          </button>
          <button
            onClick={handleSave}
            disabled={saving}
            className="px-3 py-1.5 text-xs font-medium text-white dark:text-dark-background bg-accent-magenta dark:bg-accent-cyan rounded-button hover:opacity-90 transition-opacity disabled:opacity-50"
          >
            {saving ? 'Saving...' : 'Save Changes'}
          </button>
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { Activity, Clock, Info } from 'lucide-react';
import { useSettingsStore } from '../stores/useSettingsStore';
import { useTimeTrackingStore } from '../stores/useTimeTrackingStore';

/**
 * Automatic Tracking Settings Component
 *
 * UI for configuring automatic time tracking behavior.
 */

export function AutoTrackingSettings() {
  const autoTrackingSettings = useSettingsStore((s) => s.autoTrackingSettings);
  const setAutoTrackingSettings = useSettingsStore((s) => s.setAutoTrackingSettings);
  const setAutomaticTracking = useTimeTrackingStore((s) => s.setAutomaticTracking);
  const setAutoStartThreshold = useTimeTrackingStore((s) => s.setAutoStartThreshold);

  const [enabled, setEnabled] = useState(autoTrackingSettings.enabled);
  const [threshold, setThreshold] = useState(autoTrackingSettings.autoStartThreshold);
  const [stopOnIdle, setStopOnIdle] = useState(autoTrackingSettings.autoStopOnIdle);

  const handleEnabledChange = (value: boolean) => {
    setEnabled(value);
    setAutoTrackingSettings({ enabled: value });
    setAutomaticTracking(value);
  };

  const handleThresholdChange = (value: number) => {
    setThreshold(value);
    setAutoTrackingSettings({ autoStartThreshold: value });
    setAutoStartThreshold(value);
  };

  const handleStopOnIdleChange = (value: boolean) => {
    setStopOnIdle(value);
    setAutoTrackingSettings({ autoStopOnIdle: value });
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center gap-3">
        <Activity className="w-6 h-6 text-accent-magenta dark:text-accent-cyan" />
        <div>
          <h2 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary">
            Automatic Time Tracking
          </h2>
          <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
            Track time automatically based on your activity
          </p>
        </div>
      </div>

      {/* Info Banner */}
      <div className="flex gap-3 p-4 bg-blue-500/10 border border-blue-500/20 rounded-lg">
        <Info className="w-5 h-5 text-blue-600 dark:text-blue-400 flex-shrink-0 mt-0.5" />
        <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
          <p className="font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
            How it works
          </p>
          <p>
            When enabled, Neuman Brain will automatically start tracking time when you:
          </p>
          <ul className="list-disc list-inside mt-2 space-y-1 ml-2">
            <li>Stay on a page for the threshold duration</li>
            <li>Focus on a specific task or note</li>
            <li>Keep working without going idle</li>
          </ul>
          <p className="mt-2">
            Entries are tagged with "Automatic" so you can easily identify them.
          </p>
        </div>
      </div>

      {/* Settings */}
      <div className="space-y-4">
        {/* Enable/Disable */}
        <div className="flex items-center justify-between p-4 bg-surface-light-secondary/50 dark:bg-surface-dark-secondary/50 rounded-lg border border-border-light dark:border-border-dark">
          <div>
            <p className="font-medium text-text-light-primary dark:text-text-dark-primary">
              Enable Automatic Tracking
            </p>
            <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
              Start tracking time automatically when you work
            </p>
          </div>
          <button
            onClick={() => handleEnabledChange(!enabled)}
            className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
              enabled
                ? 'bg-accent-magenta dark:bg-accent-cyan'
                : 'bg-surface-light-tertiary dark:bg-surface-dark-tertiary'
            }`}
          >
            <span
              className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                enabled ? 'translate-x-6' : 'translate-x-1'
              }`}
            />
          </button>
        </div>

        {/* Auto-Start Threshold */}
        <div className="p-4 bg-surface-light-secondary/50 dark:bg-surface-dark-secondary/50 rounded-lg border border-border-light dark:border-border-dark">
          <div className="flex items-center justify-between mb-3">
            <div className="flex items-center gap-2">
              <Clock className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
              <p className="font-medium text-text-light-primary dark:text-text-dark-primary">
                Auto-Start Threshold
              </p>
            </div>
            <span className="text-sm font-mono text-accent-magenta dark:text-accent-cyan">
              {threshold}s
            </span>
          </div>
          <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary mb-3">
            How long to stay in a context before automatically starting a timer
          </p>
          <input
            type="range"
            min="10"
            max="120"
            step="5"
            value={threshold}
            onChange={(e) => handleThresholdChange(Number(e.target.value))}
            disabled={!enabled}
            className="w-full h-2 bg-surface-light-tertiary dark:bg-surface-dark-tertiary rounded-lg appearance-none cursor-pointer accent-accent-magenta dark:accent-accent-cyan disabled:opacity-50"
          />
          <div className="flex justify-between text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
            <span>10s (Immediate)</span>
            <span>60s (Balanced)</span>
            <span>120s (Patient)</span>
          </div>
        </div>

        {/* Auto-Stop on Idle */}
        <div className="flex items-center justify-between p-4 bg-surface-light-secondary/50 dark:bg-surface-dark-secondary/50 rounded-lg border border-border-light dark:border-border-dark">
          <div>
            <p className="font-medium text-text-light-primary dark:text-text-dark-primary">
              Stop on Idle
            </p>
            <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
              Automatically stop tracking when you go idle
            </p>
          </div>
          <button
            onClick={() => handleStopOnIdleChange(!stopOnIdle)}
            disabled={!enabled}
            className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors disabled:opacity-50 ${
              stopOnIdle
                ? 'bg-accent-magenta dark:bg-accent-cyan'
                : 'bg-surface-light-tertiary dark:bg-surface-dark-tertiary'
            }`}
          >
            <span
              className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                stopOnIdle ? 'translate-x-6' : 'translate-x-1'
              }`}
            />
          </button>
        </div>
      </div>

      {/* Preview */}
      {enabled && (
        <div className="p-4 bg-green-500/10 border border-green-500/20 rounded-lg">
          <p className="text-sm font-medium text-green-600 dark:text-green-400 mb-2">
            ✓ Automatic tracking is active
          </p>
          <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
            Stay on a page or task for {threshold} seconds to automatically start tracking.
            {stopOnIdle && ' Timer will stop when you go idle.'}
          </p>
        </div>
      )}
    </div>
  );
}

