          description: entry.description,
          startTime: entry.startTime,
          endTime: entry.endTime,
          duration: entry.duration,
          tags: entry.tags || [],
          billable: entry.billable,
          notes: entry.notes,
          projectIds: [],
        };

        await addManualEntry(cleanEntry);
        importedCount++;
      }

      // Reload entries to show newly imported data
      await loadEntries();

      setImportResult({
        type: 'success',
        message: `Imported ${importedCount} time ${importedCount === 1 ? 'entry' : 'entries'} and created ${togglProjects.length} ${togglProjects.length === 1 ? 'project' : 'projects'} from Toggl`,
        count: importedCount,
      });

      // Auto-close after 3 seconds
      setTimeout(() => {
        onClose();
      }, 3000);
    } catch (error) {
      setImportResult({
        type: 'error',
        message: error instanceof Error ? error.message : 'Import failed',
      });
    }
  };

  const handleUploadClick = () => {
    fileInputRef.current?.click();
  };

  const handleReset = () => {
    setImportResult(null);
    setIsProcessing(false);
    // Reset file input
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="Import Time Entries from Toggl" maxWidth="md">
      <div className="space-y-4">
        {/* File Upload */}
        {!importResult && (
          <div className="space-y-4">
            <div className="flex items-center gap-4 p-4 rounded-lg border-2 border-border-light dark:border-border-dark bg-surface-light-elevated dark:bg-surface-dark-elevated">
              <div className="flex-shrink-0 w-12 h-12 rounded-full bg-gradient-to-br from-accent-magenta to-accent-purple flex items-center justify-center">
                <Clock className="w-6 h-6 text-white" />
              </div>
              <div className="flex-1">
                <h3 className="text-base font-semibold text-text-light-primary dark:text-text-dark-primary">
                  Toggl Track CSV Import
                </h3>
                <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                  Import time entries and projects from your Toggl export
                </p>
              </div>
            </div>

            <div
              onClick={handleUploadClick}
              className="relative flex flex-col items-center justify-center gap-3 p-8 border-2 border-dashed border-border-light dark:border-border-dark rounded-lg hover:border-accent-magenta dark:hover:border-accent-cyan hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-all duration-standard ease-smooth cursor-pointer group"
            >
              <Upload className="w-10 h-10 text-text-light-secondary dark:text-text-dark-secondary group-hover:text-accent-magenta dark:group-hover:text-accent-cyan transition-colors" />
              <div className="text-center">
                <p className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
                  {isProcessing ? 'Processing...' : 'Click to upload CSV file'}
                </p>
                <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
                  CSV file from Toggl Track export
                </p>
              </div>
              <input
                ref={fileInputRef}
                type="file"
                accept=".csv"
                onChange={handleFileSelect}
                className="hidden"
                disabled={isProcessing}
              />
            </div>

            <div className="bg-accent-blue/10 dark:bg-accent-blue/20 border border-accent-blue/20 dark:border-accent-blue/30 rounded-lg p-3">
              <p className="text-xs text-text-light-primary dark:text-text-dark-primary font-medium mb-1">
                How to export from Toggl:
              </p>
              <ol className="text-xs text-text-light-secondary dark:text-text-dark-secondary space-y-1 list-decimal list-inside">
                <li>Go to Toggl Track: Settings → Data Export</li>
                <li>Select date range and click "Download CSV"</li>
                <li>Upload the CSV file here</li>
              </ol>
              <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mt-2">
                Projects will be automatically created if they don't exist.
              </p>
            </div>
          </div>
        )}

        {/* Import Result */}
        {importResult && (
          <div className={`flex items-start gap-3 p-4 rounded-lg ${
            importResult.type === 'success'
              ? 'bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800'
              : 'bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800'
          }`}>
            {importResult.type === 'success' ? (
              <CheckCircle className="w-5 h-5 text-green-600 dark:text-green-400 flex-shrink-0 mt-0.5" />
            ) : (
              <AlertCircle className="w-5 h-5 text-red-600 dark:text-red-400 flex-shrink-0 mt-0.5" />
            )}
            <div className="flex-1">
              <p className={`text-sm font-medium ${
                importResult.type === 'success'
                  ? 'text-green-900 dark:text-green-100'
                  : 'text-red-900 dark:text-red-100'
              }`}>
                {importResult.message}
              </p>
            </div>
          </div>
        )}

        {importResult && importResult.type === 'error' && (
          <div className="flex gap-2">
            <button
              onClick={handleReset}
              className="flex-1 px-4 py-2 rounded-button bg-gradient-button-primary hover:shadow-glow-magenta text-white font-medium transition-all duration-standard ease-smooth"
            >
              Try Again
            </button>
            <button
              onClick={onClose}
              className="px-4 py-2 rounded-button border border-border-light dark:border-border-dark text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-all duration-standard ease-smooth"
            >
              Close
            </button>
          </div>
        )}
      </div>
    </Modal>
  );
};

import { useState, useEffect } from 'react';
import { X, Clock, Calendar } from 'lucide-react';
import { useTimeTrackingStore } from '../stores/useTimeTrackingStore';
import { ProjectSelector } from './ProjectSelector';

interface ManualTimeEntryModalProps {
  onClose: () => void;
}

type DurationMode = 'endTime' | 'duration';

/**
 * ManualTimeEntryModal Component
 * Modal dialog for creating time entries without running a timer
 */
export function ManualTimeEntryModal({ onClose }: ManualTimeEntryModalProps) {
  const { addManualEntry } = useTimeTrackingStore();

  // Form state
  const [description, setDescription] = useState('');
  const [projectId, setProjectId] = useState<string | null>(null);
  const [startTime, setStartTime] = useState('');
  const [endTime, setEndTime] = useState('');
  const [durationHours, setDurationHours] = useState('0');
  const [durationMinutes, setDurationMinutes] = useState('30');
  const [notes, setNotes] = useState('');
  const [durationMode, setDurationMode] = useState<DurationMode>('duration');
  const [billable, setBillable] = useState(false);
  const [hourlyRate, setHourlyRate] = useState('');

  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');

  // Initialize start time to current time
  useEffect(() => {
    const now = new Date();
    const formatDateTimeLocal = (date: Date) => {
      return date.toISOString().slice(0, 16);
    };
    setStartTime(formatDateTimeLocal(now));
  }, []);

  // Calculate duration for preview
  const calculateDuration = (): { hours: number; minutes: number; seconds: number } | null => {
    if (!startTime) return null;

    if (durationMode === 'endTime') {
      if (!endTime) return null;
      const start = new Date(startTime).getTime();
      const end = new Date(endTime).getTime();
      if (end <= start) return null;

      const durationSeconds = Math.floor((end - start) / 1000);
      const hours = Math.floor(durationSeconds / 3600);
      const minutes = Math.floor((durationSeconds % 3600) / 60);
      return { hours, minutes, seconds: durationSeconds };
    } else {
      const hours = parseInt(durationHours) || 0;
      const minutes = parseInt(durationMinutes) || 0;
      const seconds = hours * 3600 + minutes * 60;
      return { hours, minutes, seconds };
    }
  };

  const handleSave = async () => {
    setError('');

    // Validation
    if (!description.trim()) {
      setError('Description is required');
      return;
    }

    if (!startTime) {
      setError('Start time is required');
      return;
    }

    const duration = calculateDuration();
    if (!duration || duration.seconds <= 0) {
      setError(durationMode === 'endTime'
        ? 'End time must be after start time'
        : 'Duration must be greater than 0');
      return;
    }

    setSaving(true);
    try {
      const startDate = new Date(startTime);
      const endDate = durationMode === 'endTime'
        ? new Date(endTime)
        : new Date(startDate.getTime() + duration.seconds * 1000);

      await addManualEntry({
        description: description.trim(),
        startTime: startDate.toISOString(),
        endTime: endDate.toISOString(),
        duration: duration.seconds,
        projectId: projectId || undefined,
        notes: notes.trim() || undefined,
        tags: [],
        billable,
        hourlyRate: hourlyRate ? parseFloat(hourlyRate) : undefined,
        projectIds: [],
      });

      onClose();
    } catch (err) {
      console.error('Failed to create entry:', err);
      setError('Failed to create entry. Please try again.');
    } finally {
      setSaving(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Escape') {
      onClose();
    } else if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) {
      handleSave();
    }
  };

  const duration = calculateDuration();

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4"
      onClick={onClose}
    >
      <div
        className="bg-surface-light dark:bg-surface-dark rounded-button border border-border-light dark:border-border-dark shadow-xl max-w-lg w-full max-h-[90vh] overflow-y-auto"
        onClick={(e) => e.stopPropagation()}
        onKeyDown={handleKeyDown}
      >
        {/* Header */}
        <div className="flex items-center justify-between px-4 py-3 border-b border-border-light dark:border-border-dark sticky top-0 bg-surface-light dark:bg-surface-dark z-10">
          <div className="flex items-center gap-2">
            <Clock className="w-4 h-4 text-accent-magenta dark:text-accent-cyan" />
            <h2 className="text-base font-semibold text-text-light-primary dark:text-text-dark-primary">
              Add Manual Time Entry
            </h2>
          </div>
          <button
            onClick={onClose}
            className="p-1 rounded-button hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary transition-all duration-standard ease-smooth"
            aria-label="Close modal"
          >
            <X className="w-4 h-4" />
          </button>
        </div>

        {/* Body */}
        <div className="p-4 space-y-3">
          {error && (
            <div className="px-3 py-2 bg-status-error/10 border border-status-error/20 rounded-button text-status-error text-xs">
              {error}
            </div>
          )}

          {/* Description */}
          <div>
            <label
              htmlFor="description"
              className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5"
            >
              Description *
            </label>
            <input
              id="description"
              type="text"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              autoFocus
              className="w-full px-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary"
              placeholder="What did you work on?"
            />
          </div>

          {/* Project */}
          <div>
            <label
              htmlFor="project"
              className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5"
            >
              Project
            </label>
            <ProjectSelector
              value={projectId}
              onChange={setProjectId}
              placeholder="No Project"
              showNoProject={true}
            />
          </div>

          {/* Start Time */}
          <div>
            <label
              htmlFor="startTime"
              className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5"
            >
              Start Time *
            </label>
            <div className="relative">
              <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-text-light-secondary dark:text-text-dark-secondary pointer-events-none" />
              <input
                id="startTime"
                type="datetime-local"
                value={startTime}
                onChange={(e) => setStartTime(e.target.value)}
                className="w-full pl-9 pr-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
              />
            </div>
          </div>

          {/* Duration Mode Toggle */}
          <div>
            <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5">
              Duration Mode
            </label>
            <div className="flex gap-2">
              <button
                type="button"
                onClick={() => setDurationMode('duration')}
                className={`flex-1 px-2.5 py-1.5 text-xs font-medium rounded-button transition-all duration-standard ease-smooth ${
                  durationMode === 'duration'
                    ? 'bg-accent-magenta dark:bg-accent-cyan text-white dark:text-dark-background'
                    : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary border border-border-light dark:border-border-dark hover:bg-surface-light dark:hover:bg-neutral-800'
                }`}
              >
                Duration
              </button>
              <button
                type="button"
                onClick={() => setDurationMode('endTime')}
                className={`flex-1 px-2.5 py-1.5 text-xs font-medium rounded-button transition-all duration-standard ease-smooth ${
                  durationMode === 'endTime'
                    ? 'bg-accent-magenta dark:bg-accent-cyan text-white dark:text-dark-background'
                    : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary border border-border-light dark:border-border-dark hover:bg-surface-light dark:hover:bg-neutral-800'
                }`}
              >
                End Time
              </button>
            </div>
          </div>

          {/* Duration or End Time Input */}
          {durationMode === 'endTime' ? (
            <div>
              <label
                htmlFor="endTime"
                className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5"
              >
                End Time *
              </label>
              <div className="relative">
                <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-text-light-secondary dark:text-text-dark-secondary pointer-events-none" />
                <input
                  id="endTime"
                  type="datetime-local"
                  value={endTime}
                  onChange={(e) => setEndTime(e.target.value)}
                  className="w-full pl-9 pr-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
                />
              </div>
            </div>
          ) : (
            <div className="grid grid-cols-2 gap-2">
              <div>
                <label
                  htmlFor="durationHours"
                  className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5"
                >
                  Hours
                </label>
                <input
                  id="durationHours"
                  type="number"
                  min="0"
                  max="23"
                  value={durationHours}
                  onChange={(e) => setDurationHours(e.target.value)}
                  className="w-full px-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
                />
              </div>
              <div>
                <label
                  htmlFor="durationMinutes"
                  className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5"
                >
                  Minutes
                </label>
                <input
                  id="durationMinutes"
                  type="number"
                  min="0"
                  max="59"
                  value={durationMinutes}
                  onChange={(e) => setDurationMinutes(e.target.value)}
                  className="w-full px-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
                />
              </div>
            </div>
